.zo-game-root--reverse-horror-pattern-hunter{max-width:860px;margin:0 auto;padding:18px;border-radius:24px;background:linear-gradient(180deg,#130f18,#26152f);color:#f7efff;font-family:Georgia,serif}.zo-game-root--reverse-horror-pattern-hunter *{box-sizing:border-box}.rh-grid{display:grid;grid-template-columns:1.5fr .9fr;gap:14px}.rh-board{display:grid;grid-template-columns:repeat(10,1fr);gap:4px;background:#0f0c14;padding:10px;border-radius:18px}.rh-cell{aspect-ratio:1;border-radius:10px;background:#1c1724;display:flex;align-items:center;justify-content:center;font-size:22px}.rh-wall{background:#473b52}.rh-exit{background:#143f37}.rh-hot{box-shadow:inset 0 0 0 2px rgba(255,116,87,.35)}.rh-panel{background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:18px;padding:14px}.rh-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin:0 0 14px}.rh-stat{background:rgba(255,255,255,.06);border-radius:14px;padding:10px}.rh-stat strong{display:block;font-size:12px;color:#d8c4e7;text-transform:uppercase}.rh-buttons,.rh-moves{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px}.rh-btn{border:0;border-radius:12px;padding:10px 14px;background:#ff7a5c;color:#fff;font-weight:700;cursor:pointer}.rh-btn--ghost{background:#335d63}.rh-log{font-size:13px;line-height:1.5;color:#e0d4eb;min-height:70px}@media (max-width:780px){.rh-grid{grid-template-columns:1fr}.rh-stats{grid-template-columns:repeat(2,1fr)}}
