$js=<<<'JS'
document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.zo-game-root--reverse-horror-pattern-hunter').forEach(function(root){const boardEl=root.querySelector('[data-board]'),logEl=root.querySelector('[data-log]'),turnEl=root.querySelector('[data-turn]'),capEl=root.querySelector('[data-captures]'),learnEl=root.querySelector('[data-learn]'),routeEl=root.querySelector('[data-route]');const walls=new Set(['4,1','4,2','4,3','4,5','4,6','5,3','6,3','7,3','2,6','3,6']);const exits=['9,1','9,8'];let state;function key(x,y){return x+','+y}function walk(x,y){return x>=0&&y>=0&&x<10&&y<10&&!walls.has(key(x,y))}function region(x,y){if(y<3)return'north';if(y>6)return'south';return'center'}function reset(){state={monster:{x:1,y:4},survivors:[{x:8,y:2},{x:7,y:7},{x:8,y:5}],heat:{},turns:18,captures:0,learning:0,route:'testing',log:'You are the monster. Herd the campers, then ambush the safe route.'};render()}function addHeat(x,y,p){for(let yy=Math.max(0,y-1);yy<=Math.min(9,y+1);yy++){for(let xx=Math.max(0,x-1);xx<=Math.min(9,x+1);xx++){const k=key(xx,yy);state.heat[k]=(state.heat[k]||0)+p-(Math.abs(xx-x)+Math.abs(yy-y))}}}function bestStep(s){const opts=[[1,0],[-1,0],[0,1],[0,-1]].map(d=>({x:s.x+d[0],y:s.y+d[1]})).filter(c=>walk(c.x,c.y));if(!opts.length)return s;opts.sort(function(a,b){const da=score(a),db=score(b);return da-db});return opts[0];function score(c){const exitDist=Math.min(...exits.map(function(e){const p=e.split(',');return Math.abs(c.x-Number(p[0]))+Math.abs(c.y-Number(p[1]))}));const monsterDist=Math.abs(c.x-state.monster.x)+Math.abs(c.y-state.monster.y);return exitDist*2+(state.heat[key(c.x,c.y)]||0)*4+(monsterDist<3?30-monsterDist*8:0)}}function updateLearning(){const counts={north:0,south:0};Object.keys(state.heat).forEach(function(k){const p=k.split(',');const r=region(Number(p[0]),Number(p[1]));if(r!=='center'){counts[r]+=state.heat[k]||0}});state.route=counts.north>counts.south?'south corridor':'north corridor';state.learning=Math.max(0,Math.min(100,Math.round(Math.max(counts.north,counts.south)*8)))}function step(dx,dy,roar){if(state.turns<=0)return;const nx=state.monster.x+dx,ny=state.monster.y+dy;if(walk(nx,ny)){state.monster.x=nx;state.monster.y=ny}addHeat(state.monster.x,state.monster.y,roar?4:1.4);if(roar){state.log='Your roar poisons the area. Survivors reroute away from your trail.'}state.survivors=state.survivors.filter(function(s){if(s.x===state.monster.x&&s.y===state.monster.y){state.captures++;state.log='A survivor disappears into the dark.';return false}return true}).map(function(s){const n=bestStep(s);if(n.x===state.monster.x&&n.y===state.monster.y){state.captures++;state.log='A panicked survivor runs straight into you.';return null}if(exits.includes(key(n.x,n.y))){state.log='A survivor escaped by trusting a new route.';return null}return{x:n.x,y:n.y}}).filter(Boolean);state.turns--;updateLearning();if(!state.survivors.length||state.turns===0){state.log=state.captures>=2?'Night belongs to you.':'Dawn breaks. Fake one corridor, then punish the other.'}render()}function render(){boardEl.innerHTML='';for(let y=0;y<10;y++){for(let x=0;x<10;x++){const cell=document.createElement('div');cell.className='rh-cell';const k=key(x,y);if(walls.has(k))cell.classList.add('rh-wall');if(exits.includes(k)){cell.classList.add('rh-exit');cell.textContent='E'}if((state.heat[k]||0)>1.8)cell.classList.add('rh-hot');if(state.monster.x===x&&state.monster.y===y)cell.textContent='M';state.survivors.forEach(function(s){if(s.x===x&&s.y===y)cell.textContent='😱'});boardEl.appendChild(cell)}}turnEl.textContent=String(state.turns);capEl.textContent=state.captures+'/3';learnEl.textContent=state.learning+'%';routeEl.textContent=state.route;logEl.textContent=state.log}root.querySelectorAll('[data-move]').forEach(function(btn){btn.addEventListener('click',function(){const m=btn.getAttribute('data-move');if(m==='up')step(0,-1,false);if(m==='down')step(0,1,false);if(m==='left')step(-1,0,false);if(m==='right')step(1,0,false)})});root.querySelector('[data-roar]').addEventListener('click',function(){step(0,0,true)});root.querySelector('[data-restart]').addEventListener('click',reset);root.addEventListener('keydown',function(e){if(e.key==='ArrowUp'||e.key==='w')step(0,-1,false);if(e.key==='ArrowDown'||e.key==='s')step(0,1,false);if(e.key==='ArrowLeft'||e.key==='a')step(-1,0,false);if(e.key==='ArrowRight'||e.key==='d')step(1,0,false);if(e.key===' ')step(0,0,true)});reset()})});
JS;
